#include "encoder_as5600.h"
#include <Wire.h>
#include <AS5600.h>
static AS5600 enc;
static float _angle=0,_rpm=0;static uint16_t _raw=0;static unsigned long _l=0;static float _lastAngle=0;
void as5600_setup(){Wire.begin();Serial.println("[as5600] OK");}
void as5600_loop(){if(millis()-_l<50)return;unsigned long dt=millis()-_l;_l=millis();_raw=enc.readAngle();_angle=_raw*360.0/4096.0;float da=_angle-_lastAngle;if(da>180)da-=360;if(da<-180)da+=360;_rpm=da/360.0*60000.0/dt;_lastAngle=_angle;}
float as5600_get_angle(){return _angle;}
uint16_t as5600_get_raw(){return _raw;}
float as5600_get_rpm(){return _rpm;}
